import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"素娥星斗靴","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/素娥星斗靴.md","filePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/素娥星斗靴.md"}'),d={name:"4.资源分区/7.物品与装备/4.奇物/1.D级/素娥星斗靴.md"};function p(_,a,l,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"素娥星斗靴",tabindex:"-1"},[s("素娥星斗靴 "),e("a",{class:"header-anchor",href:"#素娥星斗靴","aria-label":'Permalink to "素娥星斗靴"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"新世短歌038")])])],-1),o('<h1 id="素娥星斗靴-1" tabindex="-1">素娥星斗靴 <a class="header-anchor" href="#素娥星斗靴-1" aria-label="Permalink to &quot;素娥星斗靴&quot;">​</a></h1><p>素娥星斗靴</p><p>价格：D+1000<br> 【外观描述】<br> 墨色鹿皮短靴以陨铁丝线密缝，靴面暗纹由三十六枚微型星砂铆接而成天枢星芒，远观如普通夜行靴。足弓处暗藏半透明月魄石薄片，走动时随步法折射出月晕般的光晕。靴底以特殊鞣制工艺嵌入细碎冰蚕翼粉，触地时泛起淡蓝色灵压光晕。</p><p>特性：<br> 【素娥蹑云】<br> 足踏星芒时，靴底冰蚕翼粉泛起霜色涟漪，青砖可留梅痕而不碎，薄冰能承鹤立而无纹；对于素娥星斗靴的穿戴者而言，只要他愿意，便可将自身对地面压强降低，最低可压缩至常态的 百分之一（即穿戴者实际重量不变，仅对地面压强降低），使得穿戴者可以在大部分液体表面驻足，从而踏雪无痕，踏水成漪。</p><p>【星沙逐月】<br> 三十六枚微型星砂瞬间爆散离靴飞旋，在身侧结成《步天歌》星图流转。每踏一步皆有月魄石折射的寒芒残像，腾跃时足底绽开六棱冰花托举，恍若踩着看不见的登天阶。穿戴者可以在移动时进行一次跳跃检定，跳跃时冰花托举，该次最大跳跃距离等同于人物的最大移动距离，高度则为最大移动距离的一半。落地时冰花爆散成雾笼罩全身，人物额外再本轮中获得2点遮蔽防御，且获得一层【逐月】。回合结束处于的落脚点需稳固，否则就会坠落。<br> 每一层【逐月】都会为人物最大移动距离增加五米，每个回合仅能获得一层【逐月】，【逐月】上限为星砂之数一半，即十八层，【逐月】层数会在场景结束时归零</p><p>【璇玑涤尘】<br> 靴面星砂暗合周天星辰运转之理，凡尘泥垢；血渍墨痕如若雪落寒潭，须臾凝成冰晶剥落。<br> 战斗外消耗一点能量使用，靴面寒气大盛，其上的普通污垢，残留血渍等会凝成桂花状冰片自动碎裂，常保洁净如新</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const m=r(d,[["render",p]]);export{f as __pageData,m as default};
